import { 
  Layers, Hash, Save, CheckSquare, Square, 
  Loader2, Edit, Trash2, Search, XCircle, Plus, X
} from "lucide-react";
import axios from "../api/axios";
import toast from "react-hot-toast";

const CategoryMaster = () => {
  const [exams, setExams] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [editId, setEditId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  
  // NEW: State to control form visibility
  const [isFormOpen, setIsFormOpen] = useState(false);

  const [formData, setFormData] = useState({ 
    catId: "", 
    examId: "", 
    catName: "", 
    features: [] 
  });

  const featureOptions = ["SYLLABUS", "MOCK TEST", "PYQ", "STUDY MATERIAL", "VIDEOS"];

  const fetchData = async () => {
    setLoading(true);
    try {
      const [exRes, catRes, idRes] = await Promise.allSettled([
        axios.get("/master/exam"),
        axios.get("/master/category/all"),
        axios.get("/master/category/next-id")
      ]);

      if (exRes.status === "fulfilled") {
        const examList = Array.isArray(exRes.value.data)
          ? exRes.value.data
          : exRes.value.data?.data || [];
        setExams(examList);
      } else {
        setExams([]);
      }

      if (catRes.status === "fulfilled") {
        const categoryList = Array.isArray(catRes.value.data)
          ? catRes.value.data
          : catRes.value.data?.data || [];
        setCategories(categoryList);
      } else {
        setCategories([]);
      }

      if (idRes.status === "fulfilled" && idRes.value.data?.nextId && !editId) {
        setFormData((prev) => ({ ...prev, catId: idRes.value.data.nextId }));
      }

      if (
        exRes.status === "rejected" ||
        catRes.status === "rejected" ||
        idRes.status === "rejected"
      ) {
        toast.error("SOME DATA FAILED TO LOAD");
      }
    } catch (err) {
      toast.error("DATABASE SYNC FAILED");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const toggleFeature = (feature) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  const openAddForm = () => {
    setEditId(null);
    setFormData({ catId: "", examId: "", catName: "", features: [] });
    fetchData(); // Get fresh ID
    setIsFormOpen(true);
  };

  const handleEdit = (cat) => {
    setEditId(cat._id);
    setFormData({
      catId: cat.catId,
      examId: cat.examId?._id || "",
      catName: cat.catName,
      features: cat.features || []
    });
    setIsFormOpen(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const res = await axios.post("/master/category/upsert", { id: editId, ...formData });
      if (res.data.success) {
        toast.success(editId ? "UPDATED" : "SAVED");
        setIsFormOpen(false);
        fetchData();
      }
    } catch (err) {
      toast.error("SAVE FAILED");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("ARE YOU SURE?")) return;
    try {
      await axios.delete(`/master/category/${id}`);
      toast.success("DELETED");
      fetchData();
    } catch (err) { toast.error("DELETE FAILED"); }
  };

  const filteredCategories = categories.filter(c => 
    c.catName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (c.examId?.examName || "").toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 max-w-7xl mx-auto font-sans relative">
      
      {/* --- HEADER SECTION --- */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-600 rounded-2xl text-white shadow-lg">
            <Layers size={24} />
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Category Master</h1>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">Manage Exam Sub-categories</p>
          </div>
        </div>

        <button 
          onClick={openAddForm}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl transition-all active:scale-95"
        >
          <Plus size={18} strokeWidth={3} />
          Add New Category
        </button>
      </div>

      {/* --- SEARCH BAR --- */}
      <div className="relative mb-6">
        <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text" 
          placeholder="SEARCH RECORDS..."
          className="w-full pl-14 pr-6 py-4 bg-white border-2 border-slate-100 rounded-[20px] font-black text-sm outline-none focus:border-blue-600 uppercase shadow-sm"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {/* --- TABLE SECTION --- */}
      <section className="bg-white rounded-[32px] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-[#0F172A] text-white text-[10px] font-black uppercase tracking-widest">
                <th className="p-5">ID</th>
                <th className="p-5">Exam</th>
                <th className="p-5">Category Name</th>
                <th className="p-5">Features</th>
                <th className="p-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan="5" className="p-20 text-center animate-pulse font-black text-slate-300 uppercase">Loading Records...</td></tr>
              ) : filteredCategories.map(cat => (
                <tr key={cat._id} className="hover:bg-blue-50/30 transition-all">
                  <td className="p-5 font-black text-blue-600 text-xs">{cat.catId}</td>
                  <td className="p-5 font-black text-slate-400 text-[10px] uppercase">{cat.examId?.examName || "---"}</td>
                  <td className="p-5 font-black text-slate-800 text-sm uppercase">{cat.catName}</td>
                  <td className="p-5">
                    <div className="flex flex-wrap gap-1">
                      {cat.features.slice(0, 2).map(f => (
                        <span key={f} className="px-2 py-1 bg-slate-100 text-slate-500 rounded-md text-[8px] font-bold">{f}</span>
                      ))}
                      {cat.features.length > 2 && <span className="text-[8px] font-bold text-blue-500">+{cat.features.length - 2} More</span>}
                    </div>
                  </td>
                  <td className="p-5 flex justify-center gap-2">
                    <button onClick={() => handleEdit(cat)} className="p-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all">
                      <Edit size={16} />
                    </button>
                    <button onClick={() => handleDelete(cat._id)} className="p-2 bg-red-50 text-red-400 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      {/* --- MODAL FORM --- */}
      {isFormOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsFormOpen(false)}></div>
          
          <form 
            onSubmit={handleSubmit}
            className="relative bg-white w-full max-w-2xl p-8 md:p-12 rounded-[40px] shadow-2xl overflow-y-auto max-h-[90vh]"
          >
            <div className="flex justify-between items-center mb-8">
              <div>
                <h2 className="text-2xl font-black uppercase tracking-tighter">{editId ? "Update" : "Add"} Category</h2>
                <p className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">Master Entry Form</p>
              </div>
              <button type="button" onClick={() => setIsFormOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-all">
                <X size={24} />
              </button>
            </div>

            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Category ID</label>
                  <div className="flex items-center gap-3 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black text-blue-600">
                    <Hash size={16} /> {formData.catId || "GENERATING..."}
                  </div>
                </div>
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Parent Exam</label>
                  <select 
                    required
                    className="w-full p-4 bg-white border-2 border-slate-100 rounded-2xl font-black text-sm outline-none focus:border-blue-600 uppercase"
                    value={formData.examId}
                    onChange={(e) => setFormData({...formData, examId: e.target.value})}
                  >
                    <option value="">-- SELECT EXAM --</option>
                    {exams.map((ex) => (
                      <option key={ex._id} value={ex._id}>
                        {ex.examCode ? `${ex.examCode} - ${ex.examName}` : ex.examName}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block">Category Name</label>
                <input 
                  required
                  type="text"
                  className="w-full p-4 border-2 border-slate-100 rounded-2xl font-black text-sm outline-none focus:border-blue-600 uppercase"
                  value={formData.catName}
                  onChange={(e) => setFormData({...formData, catName: e.target.value.toUpperCase()})}
                />
              </div>

              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 mb-4 block">Enabled Features</label>
                <div className="grid grid-cols-2 gap-3">
                  {featureOptions.map(f => (
                    <button
                      key={f}
                      type="button"
                      onClick={() => toggleFeature(f)}
                      className={`flex items-center gap-3 p-4 rounded-xl border-2 transition-all font-black text-[10px] ${
                        formData.features.includes(f) 
                        ? "bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100" 
                        : "bg-white border-slate-100 text-slate-400"
                      }`}
                    >
                      {formData.features.includes(f) ? <CheckSquare size={16} /> : <Square size={16} />}
                      {f}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                disabled={isSaving}
                className="w-full py-5 bg-[#0F172A] text-white rounded-2xl font-black uppercase tracking-[0.2em] shadow-xl hover:bg-blue-600 transition-all flex justify-center items-center gap-3"
              >
                {isSaving ? <Loader2 className="animate-spin" /> : <Save size={20} />}
                {editId ? "Update Record" : "Save Record"}
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default CategoryMaster;
